<div class="card"><div class="card-head"><h3>Notifications</h3></div><div class="notification-list"><?php foreach ($notifications as $note): ?><div class="note-item <?= $note['is_read'] ? 'read' : 'unread' ?>"><div class="between"><strong><?= e($note['title']) ?></strong><small><?= e($note['created_at']) ?></small></div><p><?= e($note['message']) ?></p><?php if (!$note['is_read']): ?><form method="post" action="<?= base_url('index.php?route=notifications/read') ?>"><input type="hidden" name="_csrf" value="<?= csrf_token() ?>"><input type="hidden" name="id" value="<?= (int)$note['id'] ?>"><button class="btn btn-sm btn-outline" type="submit">Mark as read</button></form><?php endif; ?></div><?php endforeach; ?><?php if (!$notifications): ?><p>No notifications yet.</p><?php endif; ?></div></div>
